// State Machine Pattern
class StateMachine {
  constructor() {
    this.currentState = null;
    this.states = {};
    this.transitions = {};
  }

  addState(name, state) {
    this.states[name] = state;
  }

  addTransition(from, to) {
    if (!this.transitions[from]) {
      this.transitions[from] = [];
    }
    this.transitions[from].push(to);
  }

  changeState(newState) {
    if (this.canTransition(newState)) {
      if (this.currentState && this.currentState.exit) {
        this.currentState.exit();
      }
      this.currentState = this.states[newState];
      if (this.currentState && this.currentState.enter) {
        this.currentState.enter();
      }
    }
  }

  canTransition(toState) {
    return !this.currentState || 
           this.transitions[this.currentState.name]?.includes(toState);
  }

  update() {
    if (this.currentState && this.currentState.update) {
      this.currentState.update();
    }
  }
}

// Sử dụng
const gameSM = new StateMachine();

// Định nghĩa states
const playingState = {
  name: 'playing',
  enter: () => console.log('Game started'),
  update: () => { /* game logic */ },
  exit: () => console.log('Game paused')
};

const pausedState = {
  name: 'paused',
  enter: () => console.log('Game paused'),
  update: () => { /* pause logic */ },
  exit: () => console.log('Game resumed')
};

// Thêm states và transitions
gameSM.addState('playing', playingState);
gameSM.addState('paused', pausedState);
gameSM.addTransition('playing', 'paused');
gameSM.addTransition('paused', 'playing');

// Chuyển state
gameSM.changeState('playing'); // Game started
gameSM.changeState('paused');  // Game paused
